using TMPro;
using UnityEngine;

/// <summary>
/// Portal / activador de Provação de Gaia no mundo:
/// uma zona (Collider2D "Is Trigger") que inicia <see cref="challenge"/> via
/// <see cref="ChallengeManager.StartChallenge"/>.
///
/// ─── Modos de entrada ─────────────────────────────────────────────────────────
///
/// <b>Modo Normal</b> (requiredForm = null, requireInteraction = true):
///   Ao entrar, mostra prompt "[E] para iniciar..."; desafio começa ao premir
///   Interagir. Se requireInteraction = false ("Zona"), inicia automaticamente.
///
/// <b>Modo Forma Específica</b> (requiredForm preenchido):
///   - O portal só "acende" (pisca/brilha) quando o player está com o animal
///     exacto definido em requiredForm.
///   - Se o player não tiver esse animal desbloqueado, o portal permanece
///     bloqueado e sem reacção.
///   - O ícone do animal (<see cref="AnimalFormData.icon"/>) é mostrado no
///     <see cref="animalIconRenderer"/> acima do portal.
///   - Entrada via cima (Move.y ≥ upEnterThreshold) — NÃO via Interagir.
///   - Durante o desafio, o player não pode trocar de forma
///     (<see cref="ChallengeDefinition.lockFormDuringChallenge"/> é forçado
///     a true ao iniciar o desafio).
///   - requireInteraction é ignorado (sempre modo "portal com Up").
///
/// ─── Outros campos ────────────────────────────────────────────────────────────
///
/// Posição de regresso: define <see cref="entryPoint"/> para usar um ponto
/// fixo em vez da posição do player ao entrar.
///
/// Abandono: se o jogador saír desta zona enquanto ESTE desafio estiver activo,
/// termina-o como Abandonado (ver <see cref="abandonOnExit"/>).
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class ChallengeTrigger : MonoBehaviour
{
    [Header("Desafio")]
    public ChallengeDefinition challenge;

    [Header("Modo Normal (sem Forma Específica)")]
    [Tooltip("true = \"Portal\" (mostra prompt, inicia ao premir Interagir). false = \"Zona\" (inicia automaticamente ao entrar). Ignorado quando 'requiredForm' está definido.")]
    public bool requireInteraction = true;

    [Header("Forma Específica (Portal Especializado)")]
    [Tooltip("Se definido, o desafio SÓ pode ser iniciado com esta forma exacta. O portal acende apenas quando o player está nessa forma, o player não pode trocar de forma durante o desafio, e a entrada é feita premindo cima (não Interagir). O ícone da forma é exibido em 'animalIconRenderer'.")]
    public AnimalFormData requiredForm;

    [Tooltip("SpriteRenderer (normalmente filho deste GameObject, posicionado acima do portal) onde é mostrado o ícone do animal exigido. Activado apenas quando 'requiredForm' está definido.")]
    public SpriteRenderer animalIconRenderer;

    [Tooltip("Eixo Y mínimo do Move para considerar que o player premiu cima (0.5 = metade do stick/D-Pad). Usado apenas no modo Forma Específica.")]
    [Range(0.3f, 1f)]
    public float upEnterThreshold = 0.55f;

    [Header("Prompts (apenas modo Normal com requireInteraction)")]
    [Tooltip("Texto do prompt de interacção. \"{0}\" é substituído por ChallengeDefinition.displayName.")]
    public string promptFormat = "Aperta [E] para iniciar \"{0}\"";

    [Tooltip("Texto mostrado quando a forma actual não pode iniciar esta Provação de Gaia (modo normal sem requiredForm). \"{0}\" é substituído por ChallengeDefinition.displayName.")]
    public string deniedFormPromptFormat = "Esta forma não pode iniciar \"{0}\"";

    [Header("Estado de Conclusão")]
    [Tooltip("Cor do glowSprite quando esta Provação de Gaia já foi concluída pelo menos uma vez. Dá ao portal uma aparência dourada/verde para indicar conclusão.")]
    public Color completedGlowColor = new Color(1f, 0.84f, 0f, 1f);   // dourado
    [Tooltip("Cor do glowSprite quando a Provação ainda não foi concluída (estado inicial).")]
    public Color defaultGlowColor = Color.white;
    [Tooltip("GameObject (ex: estrela, checkmark) activado quando a Provação de Gaia já foi concluída. Opcional — deixar vazio se só usar a cor do glow.")]
    public GameObject completedBadge;

    [Header("Info ao Aproximar (opcional — world-space TMP_Text no prefab do portal)")]
    [Tooltip("TMP_Text posicionado acima do portal que mostra o tipo da Provação de Gaia (ex: 'Combate', 'Corrida'). Activado quando o player entra na zona, escondido ao sair. Deixar vazio para desactivar.")]
    public TMP_Text challengeTypeLabel;
    [Tooltip("TMP_Text posicionado acima do portal que mostra a recompensa principal (ex: '⭐ +5 Sementes · Runa de Gaia'). Activado quando o player entra, escondido ao sair. Deixar vazio para desactivar.")]
    public TMP_Text rewardPreviewLabel;

    [Header("Posição de Regresso (opcional)")]
    [Tooltip("Se definido, o jogador volta para este ponto no fim do desafio (quando endBehavior = VoltarParaEntrada), em vez da posição que tinha ao iniciar.")]
    public Transform entryPoint;

    [Header("Abandono")]
    [Tooltip("Se o jogador saír desta zona enquanto este desafio estiver activo, termina-o como Abandonado.")]
    public bool abandonOnExit = true;

    [Header("Feedback Visual/Sonoro (opcional)")]
    [Tooltip("Activado/piscado enquanto o player está na zona com a forma correcta (ou sempre, no modo normal). No modo Forma Específica, fica desligado até a forma correcta estar equipada.")]
    public SpriteRenderer glowSprite;

    [Tooltip("Som ao entrar na zona (e ter a forma correcta, no modo Forma Específica).")]
    public AudioClip enterSfx;

    // ── Estado interno ──────────────────────────────────────────────────────

    private PlayerInputRouter _input;
    private FormSwitcher _formSwitcher;
    private bool _playerInRange;

    // Para detecção de "rising edge" do eixo Up (evita disparo contínuo).
    private bool _wasUpPressed;

    // Indica se, com a forma actual, o player pode entrar neste portal
    // (só relevante no modo Forma Específica — no modo normal é sempre true
    // se IsFormAllowed).
    private bool _formReady;

    /// <summary>True enquanto o player está dentro desta zona/portal.</summary>
    public bool PlayerInRange => _playerInRange;

    // ── Configuração ────────────────────────────────────────────────────────

    private bool IsRequiredFormMode => requiredForm != null;

    private void Reset()
    {
        var col = GetComponent<Collider2D>();
        if (col != null) col.isTrigger = true;
    }

    private void Start()
    {
        // Aplica o estado de conclusão logo no início da cena (antes de
        // qualquer interacção do player).
        RefreshCompletionVisual();

        // Info labels escondidas por defeito — só aparecem quando o player entra.
        if (challengeTypeLabel != null) challengeTypeLabel.gameObject.SetActive(false);
        if (rewardPreviewLabel != null) rewardPreviewLabel.gameObject.SetActive(false);
    }

    private void Awake()
    {
        // Configura o ícone do animal (visível apenas no modo Forma Específica).
        if (animalIconRenderer != null)
        {
            if (IsRequiredFormMode && requiredForm.icon != null)
            {
                animalIconRenderer.sprite = requiredForm.icon;
                animalIconRenderer.enabled = true;
            }
            else
            {
                animalIconRenderer.enabled = false;
            }
        }

        // Glow começa desligado no modo Forma Específica (acende quando a forma correta é equipada).
        if (glowSprite != null && IsRequiredFormMode)
            glowSprite.enabled = false;
    }

    // ── Trigger ────────────────────────────────────────────────────────────

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        _playerInRange = true;
        _wasUpPressed = false;

        _input = other.GetComponent<PlayerInputRouter>();
        _formSwitcher = other.GetComponent<FormSwitcher>()
                     ?? other.GetComponentInParent<FormSwitcher>();

        if (IsRequiredFormMode)
        {
            // Subscreve às mudanças de forma para actualizar o estado do portal em tempo real.
            if (_formSwitcher != null)
                _formSwitcher.OnFormApplied += OnFormApplied;

            // Avalia a forma actual imediatamente.
            EvaluateRequiredForm(_formSwitcher != null ? _formSwitcher.CurrentForm : null);
        }
        else
        {
            // Modo normal: glow sempre ligado ao entrar.
            if (glowSprite != null) glowSprite.enabled = true;
            if (enterSfx != null) AudioManager.Instance?.PlaySE(enterSfx);

            if (requireInteraction)
            {
                if (_input != null) _input.InteractPressed += OnInteractPressed;
                ShowNormalPrompt(other);
            }
            else
            {
                TryStartChallenge(other);
            }
        }

        // Mostra tipo da Provação e pré-visualização da recompensa ao aproximar.
        ShowInfoLabels();
    }

    private void OnTriggerExit2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        _playerInRange = false;
        _formReady = false;
        _wasUpPressed = false;

        // Desinscreve de todos os eventos.
        if (_input != null) _input.InteractPressed -= OnInteractPressed;
        _input = null;

        if (_formSwitcher != null)
            _formSwitcher.OnFormApplied -= OnFormApplied;
        _formSwitcher = null;

        // Apaga glow ao sair.
        if (glowSprite != null) glowSprite.enabled = false;

        // Esconde prompt normal ao sair.
        if (!IsRequiredFormMode && requireInteraction && InteractionPromptUI.Instance != null)
            InteractionPromptUI.Instance.Hide();

        // Abandona a Provação se o player saiu da zona.
        if (abandonOnExit && challenge != null && ChallengeManager.Instance != null
            && ChallengeManager.Instance.IsActive && ChallengeManager.Instance.CurrentChallenge == challenge)
        {
            ChallengeManager.Instance.AbandonChallenge();
        }

        // Esconde labels de info ao sair da zona.
        HideInfoLabels();
    }

    private void OnDisable()
    {
        if (_input != null) _input.InteractPressed -= OnInteractPressed;
        _input = null;

        if (_formSwitcher != null)
            _formSwitcher.OnFormApplied -= OnFormApplied;
        _formSwitcher = null;
    }

    // ── Update (detecção de "Up" no modo Forma Específica) ─────────────────

    private void Update()
    {
        if (!_playerInRange || !IsRequiredFormMode || !_formReady) return;
        if (_input == null) return;

        bool upNow = _input.Move.y >= upEnterThreshold;

        if (upNow && !_wasUpPressed)
        {
            // Rising edge de "cima" — tenta iniciar o desafio.
            var playerGo = _input.gameObject;
            var col = playerGo.GetComponent<Collider2D>()
                   ?? playerGo.GetComponentInChildren<Collider2D>();
            TryStartChallenge(col);
        }

        _wasUpPressed = upNow;
    }

    // ── Callbacks ──────────────────────────────────────────────────────────

    /// <summary>Chamado quando o player troca de forma (subscrito em OnTriggerEnter2D, modo Forma Específica).</summary>
    private void OnFormApplied(AnimalFormData form)
    {
        EvaluateRequiredForm(form);
    }

    /// <summary>
    /// Avalia se a forma actual permite entrar neste portal (modo Forma Específica).
    /// Actualiza <see cref="_formReady"/>, o glow e o som de entrada.
    /// </summary>
    private void EvaluateRequiredForm(AnimalFormData currentForm)
    {
        bool hasUnlocked = _formSwitcher != null
                           && _formSwitcher.unlockedForms.Contains(requiredForm);

        bool isCorrectForm = currentForm == requiredForm;

        bool wasReady = _formReady;
        _formReady = hasUnlocked && isCorrectForm;

        // Actualiza o glow: acende/apaga conforme a forma.
        if (glowSprite != null)
            glowSprite.enabled = _formReady;

        // Toca som de entrada apenas quando o estado muda de "não pronto" → "pronto".
        if (_formReady && !wasReady && enterSfx != null)
            AudioManager.Instance?.PlaySE(enterSfx);
    }

    private void OnInteractPressed()
    {
        if (!_playerInRange) return;
        if (_input != null && _input.InteractConsumed) return;

        var playerGo = _input != null ? _input.gameObject : PlayerLocator.GameObject;
        if (playerGo == null) return;

        var col = playerGo.GetComponent<Collider2D>()
               ?? playerGo.GetComponentInChildren<Collider2D>();

        if (TryStartChallenge(col))
            if (_input != null) _input.InteractConsumed = true;
    }

    // ── Iniciar desafio ────────────────────────────────────────────────────

    /// <summary>
    /// Tenta iniciar o desafio. No modo Forma Específica, verifica que a forma
    /// actual == requiredForm e que o player a tem desbloqueada; no modo Normal,
    /// verifica <see cref="ChallengeDefinition.IsFormAllowed"/>.
    /// Devolve true se o desafio foi iniciado.
    /// </summary>
    private bool TryStartChallenge(Collider2D playerCollider)
    {
        if (challenge == null || ChallengeManager.Instance == null || playerCollider == null)
            return false;

        var form = GetCurrentForm(playerCollider);

        if (IsRequiredFormMode)
        {
            // Porta bloqueada se o animal não está desbloqueado.
            if (_formSwitcher == null || !_formSwitcher.unlockedForms.Contains(requiredForm))
                return false;

            // Porta fechada se não está com o animal certo.
            if (form != requiredForm)
                return false;

            // Força lockFormDuringChallenge na definição ao iniciar.
            challenge.lockFormDuringChallenge = true;
        }
        else
        {
            if (!challenge.IsFormAllowed(form)) return false;
        }

        Vector3 entryPos = entryPoint != null ? entryPoint.position : playerCollider.transform.position;
        return ChallengeManager.Instance.StartChallenge(challenge, form, entryPos);
    }

    // ── Prompt (modo Normal) ───────────────────────────────────────────────

    private void ShowNormalPrompt(Collider2D playerCollider)
    {
        if (challenge == null || InteractionPromptUI.Instance == null) return;
        if (ChallengeManager.Instance != null && ChallengeManager.Instance.IsActive) return;

        var form = GetCurrentForm(playerCollider);
        string text = challenge.IsFormAllowed(form)
            ? string.Format(promptFormat, challenge.displayName)
            : string.Format(deniedFormPromptFormat, challenge.displayName);

        InteractionPromptUI.Instance.Show(text);
    }

    // ── Utilitários ────────────────────────────────────────────────────────

    private static AnimalFormData GetCurrentForm(Collider2D playerCollider)
    {
        if (playerCollider == null) return null;
        var switcher = playerCollider.GetComponent<FormSwitcher>()
                    ?? playerCollider.GetComponentInParent<FormSwitcher>();
        return switcher != null ? switcher.CurrentForm : null;
    }

    // ── Visuais de Conclusão ───────────────────────────────────────────────

    /// <summary>
    /// Actualiza a cor do glow e o badge de conclusão conforme o estado actual
    /// do desafio em PlayerProgress. Chamado em Start() e pode ser chamado
    /// manualmente após concluir a Provação (ex: pelo ChallengeManager).
    /// </summary>
    public void RefreshCompletionVisual()
    {
        bool isCompleted = challenge != null
            && PlayerProgress.Instance != null
            && PlayerProgress.Instance.HasCompletedChallenge(challenge.challengeId);

        if (glowSprite != null)
            glowSprite.color = isCompleted ? completedGlowColor : defaultGlowColor;

        if (completedBadge != null)
            completedBadge.SetActive(isCompleted);
    }

    // ── Labels de Info (tipo + recompensa) ────────────────────────────────

    private void ShowInfoLabels()
    {
        if (challenge == null) return;

        // Tipo da Provação de Gaia (ex: "Combate", "Corrida").
        if (challengeTypeLabel != null)
        {
            challengeTypeLabel.text = challenge.TypeDisplayName;
            challengeTypeLabel.gameObject.SetActive(true);
        }

        // Pré-visualização da recompensa.
        if (rewardPreviewLabel != null)
        {
            bool completed = PlayerProgress.Instance != null
                && PlayerProgress.Instance.HasCompletedChallenge(challenge.challengeId);

            // Na primeira vez mostra a recompensa primária; nas repetições, a secundária.
            var reward = (!completed || !challenge.hasSecondaryReward)
                ? challenge.primaryReward
                : challenge.secondaryReward;

            string text = BuildRewardText(reward);
            if (!string.IsNullOrEmpty(text))
            {
                rewardPreviewLabel.text = text;
                rewardPreviewLabel.gameObject.SetActive(true);
            }
        }
    }

    private void HideInfoLabels()
    {
        if (challengeTypeLabel != null) challengeTypeLabel.gameObject.SetActive(false);
        if (rewardPreviewLabel != null)  rewardPreviewLabel.gameObject.SetActive(false);
    }

    /// <summary>
    /// Constrói uma string de uma linha resumindo a recompensa (ex:
    /// "⭐ +3 Sementes · +1 Runa de Gaia · Espada"). Devolve vazio se não
    /// houver nenhuma recompensa ou a recompensa for nula.
    /// </summary>
    private static string BuildRewardText(ChallengeReward reward)
    {
        if (reward == null || !reward.HasAnything) return string.Empty;

        var parts = new System.Collections.Generic.List<string>();

        if (reward.sementes > 0)    parts.Add($"+{reward.sementes} Sementes");
        if (reward.runasDeGaia > 0) parts.Add($"+{reward.runasDeGaia} Runa{(reward.runasDeGaia > 1 ? "s" : "")} de Gaia");
        if (reward.runasDeApolo > 0) parts.Add($"+{reward.runasDeApolo} Runa{(reward.runasDeApolo > 1 ? "s" : "")} de Apolo");

        if (reward.itemRewards != null)
            foreach (var entry in reward.itemRewards)
                if (entry?.item != null)
                    parts.Add(entry.amount > 1
                        ? $"{entry.item.displayName} ×{entry.amount}"
                        : entry.item.displayName);

        return parts.Count > 0 ? string.Join("  ·  ", parts) : string.Empty;
    }
}
